## Problem1(1.5.8.65)
## Author()
## Institution()
## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "PCCmacros.pl",
  "PGchoicemacros.pl",
  "parserAssignment.pl",
  "contextForm.pl",
  "contextFraction.pl",
  "parserLinearRelation.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($X, $Y) = random_subset(2, 'a'..'n','p'..'z','A'..'D', 'F'..'N','P'..'T','V'..'Z');
do {
  @A = (-9..-1, 1..9)[NchooseK(18,2)];
  @B = (-9..-1, 1..9)[NchooseK(18,2)];
  $roll = random(0,3);
  if ($roll == 0) {$A[0] = list_random(-1,1)};
  if ($roll == 1) {$A[1] = list_random(-1,1)};
  if ($roll == 2) {$B[0] = list_random(-1,1)};
  if ($roll == 3) {$B[1] = list_random(-1,1)};
} until (abs($A[0]*$B[1] - $A[1]*$B[0]) > 1 && abs($A[0]*$B[1] - $A[1]*$B[0]) < 10);
@C = (-9..-1, 1..9)[NchooseK(18,2)];
Context("Fraction")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
parser::Assignment->Allow;
$x = Fraction(($B[1]*$C[0] - $B[0]*$C[1])/($A[0]*$B[1] - $A[1]*$B[0]));
$y = Fraction((-$A[1]*$C[0] + $A[0]*$C[1])/($A[0]*$B[1] - $A[1]*$B[0]));
$xis = Formula("$X = $x");
$yis = Formula("$Y = $y");
$solution = List($xis,$yis);
Context()->strings->remove("NONE");
Context()->strings->add(
  "no solutions" => {},
);
for (
  "no solution",
  "none",
  "there are no solutions",
  "the solution set is empty",
  "solution set is empty",
  "empty set",
  "∅",
  "{}",
  "{ }",
  "{  }",
  "{   }"
) {
  Context()->strings->add($_ => {alias => "no solutions"});
}
Context()->strings->add(
  "infinitely many solutions" => {},
);
for (
  "infinitely many",
  "infinite solution set",
  "infinite",
  "the solution set is infinite",
  "solution set is infinite"
) {
  Context()->strings->add($_ => {alias => "infinitely many solutions"});
}
$answer = $solution->cmp(
  mathQuillOpts => 'disabled'
);
Context("LinearRelation")->variables->are($X => 'Real', $Y => 'Real');
Context()->noreduce('(-x)-y', '(-x)+y');
@left = map{Formula("$A[$_] $X + $B[$_] $Y")->reduce} (0,1);
@f = map{Formula("$left[$_] = $C[$_]")->reduce} (0,1);

############################################################
# Body
############################################################

BEGIN_PGML
Solve the system of equations using substitution.

[`\newcommand{\amp}{&}\left\{
                  \begin{alignedat}{4}
                  \amp [$f[0]] \\
                  \amp [$f[1]]
                  \end{alignedat}
                  \right.
                `]

[@KeyboardInstructions('Write the solution in the format [`[$X] = \text{number}, [$Y] = \text{number}\text{.}`] If there is no solution, enter [|no solutions|]*. If there are infinitely many solutions, enter [|infinitely many solutions|]*.')@]**

[_]{$answer}{16}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
